package com.evolua.auth.application; import com.evolua.auth.domain.AuthUser; import com.evolua.auth.domain.AuthUserRepository; import com.evolua.auth.domain.RefreshSession; import com.evolua.auth.domain.RefreshSessionRepository; import com.evolua.auth.infrastructure.security.TokenIssuer; import java.time.Instant; import java.util.List; import java.util.UUID; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; @Service public class AuthService { private final AuthUserRepository authUserRepository; private final RefreshSessionRepository refreshSessionRepository; private final PasswordEncoder passwordEncoder; private final TokenIssuer tokenIssuer; public AuthService(AuthUserRepository authUserRepository, RefreshSessionRepository refreshSessionRepository, PasswordEncoder passwordEncoder, TokenIssuer tokenIssuer) { this.authUserRepository = authUserRepository; this.refreshSessionRepository = refreshSessionRepository; this.passwordEncoder = passwordEncoder; this.tokenIssuer = tokenIssuer; } @Transactional public AuthUser register(String email, String password) { authUserRepository.findByEmail(email).ifPresent(existing -> { throw new IllegalArgumentException("Email already registered"); }); return authUserRepository.save(new AuthUser(null, UUID.randomUUID().toString(), email, passwordEncoder.encode(password), List.of("ROLE_USER"), Instant.now())); } @Transactional public AuthTokens login(String email, String password) { AuthUser user = authUserRepository.findByEmail(email).orElseThrow(() -> new IllegalArgumentException("Invalid credentials")); if (!passwordEncoder.matches(password, user.passwordHash())) { throw new IllegalArgumentException("Invalid credentials"); } refreshSessionRepository.revokeAll(user.userId()); String access = tokenIssuer.accessToken(user.userId(), user.email(), user.roles()); String refresh = tokenIssuer.refreshToken(user.userId(), user.email(), user.roles()); refreshSessionRepository.save(new RefreshSession(null, user.userId(), refresh, Instant.now(), false)); return new AuthTokens(access, refresh); } @Transactional public AuthTokens refresh(String refreshToken) { RefreshSession session = refreshSessionRepository.findByRefreshToken(refreshToken).orElseThrow(() -> new IllegalArgumentException("Invalid refresh token")); if (session.revoked()) { throw new IllegalArgumentException("Refresh token revoked"); } AuthUser user = authUserRepository.findByUserId(session.userId()).orElseThrow(() -> new IllegalArgumentException("User not found")); refreshSessionRepository.revokeAll(user.userId()); String access = tokenIssuer.accessToken(user.userId(), user.email(), user.roles()); String nextRefresh = tokenIssuer.refreshToken(user.userId(), user.email(), user.roles()); refreshSessionRepository.save(new RefreshSession(null, user.userId(), nextRefresh, Instant.now(), false)); return new AuthTokens(access, nextRefresh); } public AuthUser me(String userId) { return authUserRepository.findByUserId(userId).orElseThrow(() -> new IllegalArgumentException("User not found")); } }
